mapper.select:
select student_no, student_name, concat(left(student_ssn,8),'******') as 'student_ssn', 
if(student_address is not null, if(char_length(student_address) > 10, concat(left(student_address,10),'...'),student_address), ' ***주소 미상*** ') as 'student_address',
date_format(entrance_date,'%Y/%m/%d') as 'entrance_date', absence_yn 
from tb_student


